import jibo = require('jibo');
import {BeSkill} from '@be/be-framework';
import {DisconnectCode, DisconnectReason} from 'jibo-command-protocol';

const TOUCH = 'touch';
const DISCONNECT = 'disconnect';

enum ANIM_STATE {
    OPENING,
    CLOSING,
    OPENED,
    CLOSED,
    SKIPPED
}

class Remote extends BeSkill {
    //exit reason - head touch vs connection closed vs entering error skill
    private closeReason:string = null;
    private mim:jibo.bt.behaviors.Mim = null;
    private animState:ANIM_STATE = ANIM_STATE.CLOSED;

    /**
     * Remote skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?) {
        super(assetPack);
        this.onConnectionClosed = this.onConnectionClosed.bind(this);
    }

    /**
     * Start the skill
     * @method open
     */
    open(result?:any, refresh?:boolean):void {
        if (refresh) {
            if (this.animState === ANIM_STATE.OPENED || this.animState === ANIM_STATE.OPENING) {
                this.close(() => {
                    this.open(result);
                }, null, false);
                return;
            }
        }

        if (result.nlu.intent === "silentRemote"){
            this.animState = ANIM_STATE.SKIPPED;
        }
        this._openHelper(result);
    }

    _openHelper(result?:any) {
        // force eye as the current view
        jibo.face.views.forceEyeView();
        // listen for the remote session being ended
        jibo.remote.sessionDiscarded.on(this.onConnectionClosed);

        this.closeReason = null;
        // play remote intro
        if (this.animState !== ANIM_STATE.SKIPPED){
            this.animState = ANIM_STATE.OPENING;
            this.playRemoteAnim(true)
                .then(() => {
                    this.animState = ANIM_STATE.OPENED;
                    jibo.remote.ready();
                })
                .catch((err)=>{
                    this.log.warn('issue with rom intro animation',err);
                    // proceed with ready anyway, we don't want animations failures to block the skill from opening
                    this.animState = ANIM_STATE.OPENED;
                    jibo.remote.ready();
                    //this.exit();
                });
        } else {
            jibo.remote.ready();
        }

    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done:() => void, pendingSkillName?:string, disconnect = true):void {
        // remove listener to remote service
        jibo.remote.sessionDiscarded.off(this.onConnectionClosed);
        /**
         * attempt manual disconnect of remote service, will be redundant if remote skill exitted by a disconnection
         * but if skill was closed by head touch or redirect this will make sure the connection is ended
         */
        if (disconnect && this.closeReason !== DISCONNECT) {
            //assume that if we are going back to idle, it was due to a touch
            //otherwise, we should be going to the Error skill
            if (pendingSkillName === '@be/idle') {
                this.closeReason = TOUCH;
            }
            const code = this.closeReason === TOUCH ? DisconnectCode.HeadTouchExit : DisconnectCode.RobotError;
            jibo.remote.closeConnection(code, DisconnectReason[code]);
        }

        // force eye view, then play outro animation
        if (this.animState !== ANIM_STATE.SKIPPED){
            this.animState = ANIM_STATE.CLOSING;
            this.forceEye()
            .then(() => {
                // play remote outro
                this.playRemoteAnim(false)
                    .then(() => {
                        this.animState = ANIM_STATE.CLOSED;
                        done();
                    })
                    .catch((err)=>{
                        this.log.warn('issue with rom outro animation',err);
                        this.animState = ANIM_STATE.CLOSED;
                        // Just in case, it never hurts to be careful
                        jibo.expression.setLEDColor([0, 0, 0]);
                        done();
                    });
            });
        } else {
            this.forceEye();
            // Just in case, it never hurts to be careful
            jibo.expression.setLEDColor([0, 0, 0]);
            done();
        }
    }

    // Play intro or outro mim, resolve when mim is complete
    private playRemoteAnim(intro:boolean = true): Promise<void> {
        return new Promise<void>((resolve, reject) => {
            let meta:string = intro ? 'TransitionEntry.mim' : 'TransitionExit.mim';
            try {
                this.mim = new jibo.bt.behaviors.Mim({
                    mimPath: String('mims/' + meta),
                    assetPack: this.assetPack,
                    getPromptData: null,
                    onSuccess: (results:jibo.bt.behaviors.MimResult) => {
                        this.mim.stopAndDestroy();
                        resolve();
                    },
                    onFailure: (results:jibo.bt.behaviors.MimResult) => {
                        this.log.warn('playRemoteAnim: MIM failure');
                        this.mim.stopAndDestroy();
                        reject();
                    },
                });
                this.mim.start();
            } catch (err){
                this.log.warn('There was an issue playing the' + meta + ' remote anim: ',err);
                reject();
            }
        });
    }

    private onConnectionClosed():void {
        this.closeReason = DISCONNECT;
        this.exit();
    }

    /**
     * Clean up views.
     * If a skill was chosen then views should already be closed and current view empty,
     * if currentView is not empty there was a problem and we close views
     */
    private forceEye(): Promise<void> {
        return new Promise<void>((resolve) => {
            jibo.face.views.forceEyeView(
                () => {
                    resolve();
                },
                null,
                jibo.face.views.TRANSITION.IN,
                jibo.face.views.TRANSITION.DOWN,
                ()=> {
                    this.log.error('cleanupViews() failure during forceEyeView, calling done anyway');
                    resolve();
                }
            );
        });
    }

}

module.exports = Remote;
